import http from "node:http";
import path from "node:path";
import express from "express";
import { Server as SocketIOServer, type Socket } from "socket.io";
import { RoomManager } from "../game/roomManager.js";
import type { EngineEvent } from "../game/types.js";
import { UserStore, type PublicUser } from "../store/userStore.js";

export interface AppServer {
  app: express.Express;
  httpServer: http.Server;
  io: SocketIOServer;
  roomManager: RoomManager;
  start: (port: number) => Promise<http.Server>;
  stop: () => Promise<void>;
}

interface UserContext {
  playerId: string;
  userName: string;
}

interface AuthenticatedRequest extends express.Request {
  authUser?: PublicUser;
  authToken?: string;
}

function isObject(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

function parseUserContext(req: express.Request, authUser?: PublicUser): UserContext {
  const body = isObject(req.body) ? req.body : {};
  const userId = body.userId ?? req.header("x-user-id") ?? req.query.userId ?? authUser?.id;
  const userName =
    body.userName ??
    req.header("x-user-name") ??
    req.query.userName ??
    authUser?.displayName ??
    authUser?.username ??
    "Player";

  if (typeof userId !== "string" || userId.trim().length === 0) {
    throw new Error("userId is required");
  }

  if (typeof userName !== "string" || userName.trim().length === 0) {
    throw new Error("userName is required");
  }

  return {
    playerId: userId,
    userName,
  };
}

function emitTutorialEvent(roomManager: RoomManager, io: SocketIOServer, roomId: string, event: EngineEvent): void {
  const room = roomManager.getRoomById(roomId);
  if (!room || room.roomType !== "tutorial") {
    return;
  }

  const user = room.players.find((player) => !player.isBot);
  if (!user?.socketId) {
    return;
  }

  if (event.type === "tutorial_step_changed") {
    io.to(user.socketId).emit("tutorial:stepChanged", event.payload);
    return;
  }

  if (event.type === "tutorial_hint") {
    io.to(user.socketId).emit("tutorial:hint", event.payload);
    return;
  }

  if (event.type === "tutorial_completed") {
    io.to(user.socketId).emit("tutorial:completed", event.payload);
  }
}

function sanitizeError(error: unknown): { message: string } {
  if (error instanceof Error) {
    return { message: error.message };
  }
  return { message: "Unexpected error" };
}

function readBearerToken(req: express.Request): string | null {
  const auth = req.header("authorization");
  if (!auth) {
    return null;
  }
  const [scheme, token] = auth.split(" ");
  if (scheme?.toLowerCase() !== "bearer" || !token) {
    return null;
  }
  return token.trim() || null;
}

export function createAppServer(options?: {
  tutorialReactionTimeoutMs?: number;
  multiplayerReactionTimeoutMs?: number;
  botDelayMs?: number;
  userDbPath?: string;
  staticDir?: string;
}): AppServer {
  const app = express();
  app.use(express.json());
  const userStore = new UserStore(options?.userDbPath);

  app.use((req, res, next) => {
    res.header("Access-Control-Allow-Origin", "*");
    res.header("Access-Control-Allow-Methods", "GET,POST,OPTIONS");
    res.header("Access-Control-Allow-Headers", "Content-Type, Authorization, x-user-id, x-user-name");
    if (req.method === "OPTIONS") {
      res.sendStatus(204);
      return;
    }
    next();
  });

  app.use((req, _res, next) => {
    const token = readBearerToken(req);
    if (!token) {
      next();
      return;
    }
    const user = userStore.getUserByToken(token);
    if (user) {
      (req as AuthenticatedRequest).authUser = user;
      (req as AuthenticatedRequest).authToken = token;
    }
    next();
  });

  function requireAuth(req: express.Request, res: express.Response, next: express.NextFunction): void {
    const authReq = req as AuthenticatedRequest;
    if (!authReq.authUser || !authReq.authToken) {
      res.status(401).json({ ok: false, error: "Authentication required" });
      return;
    }
    next();
