      const authReq = req as AuthenticatedRequest;
      const body = isObject(req.body) ? req.body : {};
      const displayName = typeof body.displayName === "string" ? body.displayName : undefined;
      const avatarUrl =
        typeof body.avatarUrl === "string"
          ? body.avatarUrl
          : body.avatarUrl === null
            ? null
            : undefined;

      const user = userStore.updateProfile({
        userId: authReq.authUser!.id,
        displayName,
        avatarUrl,
      });
      res.json({ ok: true, user });
    } catch (error) {
      const err = sanitizeError(error);
      res.status(400).json({ ok: false, error: err.message });
    }
  });

  app.post("/tutorial/start", (req, res) => {
    try {
      const authReq = req as AuthenticatedRequest;
      const { playerId, userName } = parseUserContext(req, authReq.authUser);
      const { room, snapshot, progress } = roomManager.startTutorial({
        userId: playerId,
        userName,
      });
      res.json({
        ok: true,
        roomId: room.roomId,
        code: room.code,
        snapshot,
        progress,
      });
    } catch (error) {
      const err = sanitizeError(error);
      res.status(400).json({ ok: false, error: err.message });
    }
  });

  app.post("/tutorial/restart", (req, res) => {
    try {
      const authReq = req as AuthenticatedRequest;
      const { playerId, userName } = parseUserContext(req, authReq.authUser);
      const { room, snapshot, progress } = roomManager.restartTutorial({
        userId: playerId,
        userName,
      });
      res.json({
        ok: true,
        roomId: room.roomId,
        code: room.code,
        snapshot,
        progress,
      });
    } catch (error) {
      const err = sanitizeError(error);
      res.status(400).json({ ok: false, error: err.message });
    }
  });

  app.get("/tutorial/progress", (req, res) => {
    try {
      const authReq = req as AuthenticatedRequest;
      const userId = req.query.userId ?? authReq.authUser?.id;
      if (typeof userId !== "string") {
        throw new Error("userId is required");
      }
      res.json({
        ok: true,
        progress: roomManager.getTutorialProgress(userId),
      });
    } catch (error) {
      const err = sanitizeError(error);
      res.status(400).json({ ok: false, error: err.message });
    }
  });

  if (options?.staticDir) {
    const staticDir = path.resolve(options.staticDir);
    app.use(express.static(staticDir, { index: false }));
    app.head("*", (req, res, next) => {
      if (req.path.startsWith("/api/") || req.path.startsWith("/tutorial/") || req.path === "/health" || req.path.startsWith("/socket.io")) {
        next();
        return;
      }
      res.status(200).end();
    });
    app.get("*", (req, res, next) => {
      if (req.method !== "GET") {
        next();
        return;
      }
      if (req.path.startsWith("/api/") || req.path.startsWith("/tutorial/") || req.path === "/health" || req.path.startsWith("/socket.io")) {
        next();
        return;
      }
      res.sendFile(path.join(staticDir, "index.html"), (error) => {
        if (error) {
          next();
        }
      });
    });
  }

  return {
    app,
    httpServer,
    io,
    roomManager,
    start: (port: number) =>
      new Promise((resolve) => {
        httpServer.listen(port, () => resolve(httpServer));
      }),
    stop: () =>
      new Promise((resolve, reject) => {
        io.close(() => {
          httpServer.close((error) => {
            if (error) {
              reject(error);
              return;
            }
            resolve();
          });
        });
      }),
  };
